} catch(err) {
  console.error("Failed to build cat:", err);
  loadingEl.textContent = "😿 加载失败...";
}

// ====================== Mute sync ======================
window.pet.getMuted().then((m) => { state.muted = !!m; });
window.pet.onMutedChange((m) => { state.muted = !!m; if (state.muted) try { audio.pause(); } catch (_) {} });

// ====================== 键盘Hook ======================
window.pet.onKeystroke(() => {
  const now = performance.now();
  const dt = state.typing.lastKey ? (now - state.typing.lastKey) / 1000 : 0.2;
  state.typing.lastKey = now;
  state.typing.rate = state.typing.rate * 0.6 + Math.min(dt > 0 ? 1/dt : 10, 20) * 0.4;
  state.typing.active = true;
  state.typing.endsAt = now + 1200;
  bumpHappiness(0.005);
});

// ====================== 语音识别 ======================
let recognition = null;
function initVoiceRecognition() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) { console.log("语音API不可用"); return; }
  recognition = new SR();
  recognition.continuous = true;
  recognition.interimResults = false;
  recognition.lang = "zh-CN";
  recognition.onresult = (e) => {
    const last = e.results[e.results.length - 1];
    if (last.isFinal) processVoiceCommand(last[0].transcript.trim());
  };
  recognition.onerror = () => { if (state.voiceEnabled) try { recognition.start(); } catch(_){} };
  recognition.onend = () => { if (state.voiceEnabled) try { recognition.start(); } catch(_){} };
}

function processVoiceCommand(text) {
  console.log("🎤", text);
  showBubble(text, "#4ade80");
  const t = text.toLowerCase();
  if (t.includes("转圈")||t.includes("跳舞")||t.includes("spin")) doSpin();
  else if (t.includes("过来")) { state.mode="walk"; state.walkTarget=state.cursor.x; state.facingDir=state.cursor.x<pivot.position.x?-1:1; state.modeUntil=performance.now()+4000; }
  else if (t.includes("坐下")) { state.mode="sit"; state.modeUntil=performance.now()+3000; }
  else if (t.includes("你好")||t.includes("hello")) { speak("你好呀！我是小土豆猫咪！🐱"); showBubble("你好呀！🐱","#fbbf24"); }
  else if (t.includes("游戏")) { state.gameMode=!state.gameMode; speak(state.gameMode?"游戏模式开启":"游戏模式关闭"); showBubble(state.gameMode?"🎮 游戏模式":"💤 普通模式","#fbbf24"); }
  else if (t.includes("测试")||t.includes("压力")) runStressTest();
  else { speak("喵~ 收到: "+text); aiRespond(text); }
}

window.pet.onVoiceToggle((v) => {
  state.voiceEnabled = v;
  if (v) { state.voiceListening=true; try { recognition.start(); } catch(_){} }
  else { state.voiceListening=false; try { recognition.stop(); } catch(_){} }
  showBubble(v?"🎤 语音已开启":"🔇 语音已关闭", v?"#4ade80":"#f87171");
});
window.pet.onGameModeToggle((v) => {
  state.gameMode=v;
  showBubble(v?"🎮 游戏模式开启":"🎮 游戏模式关闭", v?"#fbbf24":"#9ca3af");
});
window.pet.onTriggerStressTest(() => runStressTest());

// ====================== AI对话 ======================
async function aiRespond(text) {
  showBubble("思考中...","#60a5fa");
  const apiKey = localStorage.getItem("deepseek_api_key") || "";
  try {
    const resp = await fetch("https://api.deepseek.com/v1/chat/completions", {
      method:"POST",
      headers:{"Content-Type":"application/json","Authorization":"Bearer "+apiKey},
      body:JSON.stringify({model:"deepseek-chat",messages:[{role:"system",content:"你是一只可爱的橘猫'小土豆'，用简短可爱的中文回答，不超过40字，加emoji"},{role:"user",content:text}],max_tokens:80,temperature:0.8})
    });
    if (!resp.ok) throw new Error("API "+resp.status);
    const data = await resp.json();
    const reply = data.choices[0].message.content;
    showBubble(reply,"#fbbf24");
    speak(reply);
    bumpHappiness(0.1);
  } catch(err) {
    showBubble("喵~ 网络不太好 😿","#f87171");
  }
}

// ====================== 语音合成 ======================
function speak(text) {
  if (state.muted||!window.speechSynthesis) return;
  const u = new SpeechSynthesisUtterance(text);
  u.lang="zh-CN"; u.rate=1.1; u.pitch=1.2; u.volume=0.8;
  window.speechSynthesis.cancel();
  window.speechSynthesis.speak(u);
}

// ====================== 气泡文字 ======================
function showBubble(text, color) {
  bubbleEl.style.background = color;
  bubbleEl.style.opacity = "1";
  bubbleEl.textContent = text;
  state.speechTimer = performance.now() + 4000;
}

// ====================== 压力测试 ======================
async function runStressTest() {
  showBubble("🔬 压力测试...","#fbbf24");
  state.stressActive = true;
  try {
    const r = await pet.runStressTest({cpu:true,memory:true,iterations:100000,memSize:100000});
    showBubble("✅ 测试完成! CPU:"+(r.results[0]?.ms||"?")+"ms 总分:"+r.totalMs+"ms","#4ade80");
  } catch(e) { showBubble("测试失败: "+e.message,"#f87171"); }
  setTimeout(()=>{ state.stressActive=false; }, 3000);
}

// ====================== 行为 ======================
function doSpin() {
  state.mode="spin"; state.modeUntil=performance.now()+2000;
  if (!state.muted) { try { audio.loop=false; audio.playbackRate=1; audio.currentTime=0; audio.play().catch(()=>{}); } catch(_){} }
  bumpHappiness(0.25);
}

function bumpHappiness(d) { state.happiness = clamp(state.happiness+d, 0, 1); applyMood(); }
function applyMood() {
  const h = state.happiness;
  canvas.style.filter = "saturate("+(0.35+0.95*h)+") brightness("+(0.85+0.25*h)+")";
}

// ====================== 输入处理 ======================
window.addEventListener("mousemove", (e) => {
  state.cursor.x=e.clientX; state.cursor.y=e.clientY;
  if (state.dragging) {
    pivot.position.x=clamp(e.clientX-state.dragOffset.x, 60, W-60);
    pivot.position.y=clamp(H-e.clientY-state.dragOffset.y, 60, H-60);
    state.movedDuringDrag=true;
    return;
  }
  updateHover();
});
window.addEventListener("mousedown", (e) => {
  if (!state.hover||!state.catData) return;
  state.dragging=true; state.movedDuringDrag=false;
  state.dragOffset.x=e.clientX-pivot.position.x;
  state.dragOffset.y=(H-e.clientY)-pivot.position.y;
  state.mode="idle"; state.modeUntil=performance.now()+1500;
});
window.addEventListener("mouseup", () => {
  if (!state.dragging) return;
  state.dragging=false;
  if (!state.movedDuringDrag) doSpin(); else bumpHappiness(0.05);
});
window.addEventListener("resize", () => {
  W=window.innerWidth; H=window.innerHeight;
  renderer.setSize(W,H,false);
  camera.left=0; camera.right=W; camera.top=H; camera.bottom=0;
  camera.updateProjectionMatrix();
});

function updateHover() {
  if (!state.catData) return;
  const sx = pivot.position.x, sy = pivot.position.y;
  const hw = 50, hh = 100;
  const over = state.cursor.x>=sx-hw && state.cursor.x<=sx+hw && state.cursor.y>=H-sy-hh && state.cursor.y<=H-sy+20;
  if (over!==state.hover) { state.hover=over; pet.setIgnoreMouse(!over); }
}

// ====================== AI调度 ======================
function scheduleNextMode(now) {
  if (state.mode==="spin") return;
  const r = Math.random();
  if (r<0.45) { state.mode="idle"; state.modeUntil=now+2000+Math.random()*3000; }
  else if (r<0.8) { state.mode="walk"; state.walkTarget=60+Math.random()*(W-120); state.facingDir=state.walkTarget<pivot.position.x?-1:1; state.modeUntil=now+6000+Math.random()*4000; }
  else if (r<0.92) { state.mode="sit"; state.modeUntil=now+2500+Math.random()*2500; }
  else { state.mode="yawn"; state.modeUntil=now+1200+Math.random()*800; }
}

// ====================== 动画循环 ======================
const clock = new THREE.Clock();
let lastHDecay = performance.now();

function tick() {
  const now = performance.now();
  const dt = Math.min(clock.getDelta(), 0.1);

  // 幸福衰减
  if (now-lastHDecay>1000) { lastHDecay=now; state.happiness=Math.max(0,state.happiness-0.01); applyMood(); }

  // 打字
  if (state.typing.active && state.mode!=="spin") {
    bob.position.y=Math.abs(Math.sin(now/80))*5;
    if (now>=state.typing.endsAt) {
      state.typing.active=false; state.typing.rate=0;
      try { audio.pause(); } catch(_){}
      scheduleNextMode(now);
    }
  } else { state.typing.rate*=0.985; }

  // 模式
  if (state.mode==="walk") {
    const dx=state.walkTarget-pivot.position.x;
    state.facingDir=Math.sign(dx)||state.facingDir;
    if (Math.abs(dx)>2) {
      pivot.position.x+=Math.sign(dx)*Math.min(Math.abs(dx),80*dt);
      bob.position.y=Math.abs(Math.sin(now/100))*8;
    } else bob.position.y=0;
    if (now>=state.modeUntil||Math.abs(dx)<2) scheduleNextMode(now);
  } else if (state.mode==="idle") {
    bob.position.y=Math.sin(now/600)*3;
    bob.scale.set(1,1+Math.sin(now/600)*0.02,1);
    if (now>=state.modeUntil) scheduleNextMode(now);
  } else if (state.mode==="sit") {
    bob.position.y=-5; bob.scale.set(1,0.9,1);
    if (now>=state.modeUntil) { bob.scale.set(1,1,1); bob.position.y=0; scheduleNextMode(now); }
  } else if (state.mode==="yawn") {
    const t=1-(state.modeUntil-now)/2000;
    bob.scale.set(1,1+Math.sin(Math.min(1,t)*Math.PI)*0.1,1);
    if (now>=state.modeUntil) { bob.scale.set(1,1,1); scheduleNextMode(now); }
  } else if (state.mode==="spin") {
    // 转圈
    facing.rotation.y += dt * 8;
    if (now>=state.modeUntil) {
      facing.rotation.y = 0;
      try { audio.pause(); } catch(_){}
      scheduleNextMode(now);
    }
  }

  // 面向
  const tsx = state.facingDir>=0?1:-1;
  facing.scale.x += (tsx-facing.scale.x)*Math.min(1,dt*6);

  // 尾巴摇摆
  if (state.catData) {
    const wag = Math.sin(now/200)*0.3;
    state.catData.tailGroup.rotation.y = wag;
    for (let i=0;i<state.catData.tailSegments.length;i++) {
      state.catData.tailSegments[i].position.x = Math.sin(now/150+i*0.5)*0.05;
    }
    // 耳朵微动
    state.catData.group.children.forEach(c => {
      if (c.name==="head") c.rotation.z = Math.sin(now/300)*0.03;
    });
  }

  // 压力测试效果
  if (state.stressActive) {
    const intensity = Math.sin(now/200)*0.3+0.7;
    canvas.style.filter = "saturate("+intensity+") brightness("+(1+(1-intensity)*0.5)+") hue-rotate("+Math.sin(now/300)*10+"deg)";
  }

  updateHover();

  // 气泡淡出
  if (now>state.speechTimer) bubbleEl.style.opacity="0";

  renderer.render(scene, camera);
  requestAnimationFrame(tick);
}

// ====================== 启动 ======================
initVoiceRecognition();
tick();
applyMood();
scheduleNextMode(performance.now());

function clamp(v,lo,hi) { return Math.max(lo,Math.min(hi,v)); }

console.log("🐱 小土豆AI桌宠已就绪!");
console.log("  Ctrl+Shift+V = 语音 | Ctrl+Shift+G = 游戏 | Ctrl+Shift+T = 测试");
